const input = $input.first().json || {};
function normalizePhone(raw) {
  let p = String(raw || '').trim().replace(/[^\d+]/g, '');
  if (p.startsWith('00')) p = '+' + p.slice(2);
  if (!p.startsWith('+')) {
    if (p.startsWith('380')) p = '+' + p;
    else if (p.startsWith('0')) p = '+38' + p;
    else p = '+' + p;
  }
  return p;
}
const phone = normalizePhone(input.phone || input.client_phone || input.Phone || '');
const session_id = input.session_id || `voice_${Date.now()}_${Math.random().toString(16).slice(2,8)}`;
return [{ json: {
  client_name: input.client_name || input.name || input.Last_Name || 'Unknown Lead',
  company: input.company || input.Company || 'GrowthLab Lead',
  phone, client_phone: phone,
  source: input.source || 'CRM Webhook',
  business_type: input.business_type || '',
  session_id
}}];

const resp = $input.first().json || {};
const lead = $('Normalize Lead Data').item.json;
const happ_call_id = String(
  resp.call_id || resp.id || resp.conversation_id ||
  resp.chat_id || resp.call?.id || resp.data?.id || ''
);
return [{ json: { ok: true, message: 'Voice call started', happ_call_id, ...lead } }];

const err = $input.first().json || {};
const lead = $('Normalize Lead Data').item.json;
return [{ json: { ok: false, message: err.error?.message || err.message || JSON.stringify(err).slice(0,300), ...lead } }];

const b = $input.first().json || {};
const data = { ...(b.variables || {}), ...b };
return [{ json: {
  client_name: data.client_name || 'Unknown Lead',
  client_phone: data.client_phone || data.phone || '',
  company: data.company || 'GrowthLab Lead',
  business_type: data.business_type || '',
  source: data.source || 'Voice',
  session_id: data.session_id || data.call_id || data.conversation_id || `voice_${Date.now()}`
}}];
